def shuffle(array):
    global lives, select, livesTick
    select = 0
    if lives > 1:
        livesTick = 125
    lives -= 1
    for i in range(len(array) - 1, 0, -1):
        j = randrange(i + 1)
        array[i], array[j] = array[j], array[i]

