  global menu, select, lives, livesTick
  menu = 10
  if not aPressed:
    display.fill(0)
    display.blit(sprite_cup, int(0), int(0), 0)
    display.blit(sprite_cup, int(43), int(0), 0)
    display.blit(sprite_cup, int(86), int(0), 0)
