def leftButton():
	global startValue, targetValue, step, input, select, i, x, menu, item, laser, item2, meteors, coinsUpg, value, shipX, shipXchngBy
	if menu == 0:
	  shipX = shipX - shipXchngBy
	  if shipX < -4:
	    shipX = -4
	  if tone: piezo.tone(200, 50)
	  game()
	elif menu == 2:
	  buymenu2(16, 0, 2)
	  buyscrollr(0, 72, -3)
