select = 0
menu = 1
laser = 0
meteors = 0
coinsUpg = 0
mainmenu()
display.text(str(">"),0,15,Display.Color.White)
display.commit()
while True:
  buttons.scan()
  #print(menu);time.sleep(0.1)
  if menu == 0:
    temp = random.randint(0,2)
    if temp == 0 and meteors != 0:
      meteorAY += random.randint(fVA,fVB)/fVC
    elif temp == 1 and meteors != 1:
      meteorBY += random.randint(fVA,fVB)/fVC
    elif temp == 2 and meteors != 0:
      meteorCY += random.randint(fVA,fVB)/fVC
    if meteorAY >= 130:
      meteorAY = -40
    elif meteorBY >= 130:
      meteorBY = -40
    elif meteorCY >= 130:
      meteorCY = -40
    game()
    display.rect(int(0), int(21), int(cooldown+2), int(10), Display.Color.Gray, False)
    if inCooldown:
      i += 2
      display.rect(int(1), int(22), int(i), int(8), Display.Color.White, True)
      if i >= cooldown:
        i = 0
        inCooldown = False
    display.commit()
  elif menu == 10:
      minigame()
  if flicker:
    if menu == 0 or menu == 3:
      display.fill(0)
      display.commit()
      if menu == 3:
        help()
